module RefModule (count, clk, reset);
   input clk, reset;
   output [1:0] count;

   reg [1:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) 
        count <= 2'b00;
    else 
        count <= count + 1;
end

endmodule
